<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="popup-title">续费时长</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'400rpx'}">
					<view class="list-box">
						<u-cell-group :border="false">
							<u-cell-item :title="item.name" v-for="(item,index) in list" :key="index"
								@click="itemClick(item,index)" :class="{on:curr ==index}">
								<view>¥ {{item.money}}</view>
							</u-cell-item>
						</u-cell-group>
					</view>
				</scroll-view>
			</view>
			<!-- <view class="popup-footer">
				<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
			</view> -->
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			},
			show: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				popupShow: false,
				list: [],
				curr: -1,
			};
		},
		computed: {

		},
		watch: {
			show(nv) {
				this.popupShow = nv
			},
		},
		created() {

		},
		mounted() {
			this.loadData()
		},
		methods: {
			open() {},
			close() {
				this.$emit('update:show', false)
			},
			async loadData() {
				const {
					renew_data
				} = await this.$u.api.renewLevel()
				this.list = renew_data
				// if (Array.isArray(rangeLevel) && rangeLevel.length) {
				// 	this.curr = 0
				// }
			},
			handelOk() {
				this.$emit('ok', {
					editForm: this.editForm,
					specValue: this.selectedSpecValue
				})
				this.close()
			},
			itemClick(row, index) {
				this.curr = index
				this.$emit('change', row)
				this.popupShow = false
			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;
		min-height: 600rpx;

		.wrap {
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}

	.list-box {

		.on {
			background-color: #f29100 !important;
			color: #fff;
			border-radius: 10rpx;

			::v-deep {
				.u-cell__value {
					color: #fff;
				}

				.u-icon--right {
					color: #fff;
				}
			}
		}
	}
</style>